from collections import deque
from typing import List

def solve(grid: List[List[int]], k: int) -> int:
    m = len(grid)
    n = len(grid[0]) if m > 0 else 0
    visited = [[False for _ in range(n)] for _ in range(m)]
    count = 0
    for i in range(m):
        for j in range(n):
            if grid[i][j] > 0 and not visited[i][j]:
                queue = deque()
                queue.append((i, j))
                visited[i][j] = True
                sum_mod = grid[i][j] % k
                while queue:
                    x, y = queue.popleft()
                    for dx in (-1, 0, 1):
                        for dy in (-1, 0, 1):
                            if dx == 0 and dy == 0:
                                continue
                            nx = x + dx
                            ny = y + dy
                            if 0 <= nx < m and 0 <= ny < n and not visited[nx][ny] and grid[nx][ny] > 0:
                                visited[nx][ny] = True
                                queue.append((nx, ny))
                                sum_mod = (sum_mod + grid[nx][ny]) % k
                if sum_mod == 0:
                    count += 1
    return count
