from collections import deque
from typing import List

def solve(grid: List[List[int]], k: int) -> int:
    m = len(grid)
    if m == 0:
        return 0
    n = len(grid[0])
    visited = [[False for _ in range(n)] for _ in range(m)]
    count = 0

    for i in range(m):
        for j in range(n):
            if grid[i][j] > 0 and not visited[i][j]:
                queue = deque()
                queue.append((i, j))
                visited[i][j] = True
                mod = grid[i][j] % k
                while queue:
                    x, y = queue.popleft()
