    visited = [[False for _ in range(n)] for _ in range(m)]
    count = 0
    for i in range(m):
        for j in range(n):
            if grid[i][j] > 0 and not visited[i][j]:
                q = deque()
                q.append((i, j))
                visited[i][j] = True
                sum_mod = grid[i][j] % k
                while q:
                    x, y = q.popleft()
                    for dx in (-1, 0, 1):
