        for (int j = 0; j < n; ++j) {
            if (grid[i][j] > 0 && !visited[i][j]) {
                queue<pair<int, int>> q;
                q.push({i, j});
                visited[i][j] = true;
                long long sum_mod = 0;
                sum_mod = (sum_mod + grid[i][j]) % k;
                while (!q.empty()) {
                    auto [x, y] = q.front();
                    q.pop();
                    for (int dx = -1; dx <= 1; ++dx) {
                        for (int dy = -1; dy <= 1; ++dy) {
                            if (dx == 0 && dy == 0) continue;
                            int nx = x + dx;
                            int ny = y + dy;
                            if (nx >= 0 && nx < m && ny >= 0 && ny < n && !visited[nx][ny] && grid[nx][ny] > 0) {
                                visited[nx][ny] = true;
                                q.push({nx, ny});
                                sum_mod = (sum_mod + grid[nx][ny]) % k;
                            }
                        }
                    }
                }
                if (sum_mod % k == 0) {
                    ++count;
                }
            }
        }
    }
    return count;
}
